import{_ as t,o as d,c as r,ag as o}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Chmod-aliassen: Bestandsrechten-snelkoppelingen voor Shell | Dotfiles (NL)","titleTemplate":":title","description":"Vereenvoudig het beheer van bestands- en maprechten met chmod-aliassen. Snelle snelkoppelingen voor gangbare rechtenpatronen zoals 755, 644 en meer.","frontmatter":{"title":"Chmod-aliassen: Bestandsrechten-snelkoppelingen voor Shell","description":"Vereenvoudig het beheer van bestands- en maprechten met chmod-aliassen. Snelle snelkoppelingen voor gangbare rechtenpatronen zoals 755, 644 en meer.","lang":"nl-NL","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Chmod-aliassen: Bestandsrechten-snelkoppelingen voor Shell preview","canonical":"/nl/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Chmod-aliassen: Bestandsrechten-snelkoppelingen voor Shell","pageType":"docs","schemaType":"WebPage","metaTitle":"Chmod-aliassen | Dotfiles","permalink":"/nl/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"chmod aliassen, bestandsrechten, shell snelkoppelingen, dotfiles, unix rechten"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Chmod-aliassen | Dotfiles"},{"name":"twitter:description","content":"Vereenvoudig het beheer van bestands- en maprechten met chmod-aliassen."},{"name":"og:title","content":"Chmod-aliassen | Dotfiles"},{"name":"og:description","content":"Vereenvoudig het beheer van bestands- en maprechten met chmod-aliassen."},{"name":"og:image:alt","content":"Dotfiles - Eenvoudig ontworpen om bij je shell-leven te passen"},{"name":"og:locale","content":"nl_NL"}]},"headers":[],"relativePath":"nl/aliases/chmod/index.md","filePath":"nl/aliases/chmod/index.md","lastUpdated":1773010926000}'),a={name:"nl/aliases/chmod/index.md"};function n(s,e,i,c,h,l){return d(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="chmod-aliassen" tabindex="-1">Chmod-aliassen <a class="header-anchor" href="#chmod-aliassen" aria-label="Permalink to &quot;Chmod-aliassen&quot;">​</a></h1><p>Snelkoppelingen voor het beheren van bestands- en maprechten.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Dotfiles banner"></p><h2 id="overzicht" tabindex="-1">Overzicht <a class="header-anchor" href="#overzicht" aria-label="Permalink to &quot;Overzicht&quot;">​</a></h2><p>De chmod-aliassen bieden een gestroomlijnde manier om bestands- en maprechten te beheren vanaf de commandoregel. In plaats van numerieke rechtencodes te onthouden, gebruik je intuitive aliassen zoals <code>chmod_755</code> of <code>chmod_u+x</code> om snel de gewenste toegangsmodus in te stellen.</p><p>Deze aliassen zijn gedefinieerd in <code>chmod.aliases.sh</code> en worden automatisch geladen door chezmoi.</p><h2 id="referentie" tabindex="-1">Referentie <a class="header-anchor" href="#referentie" aria-label="Permalink to &quot;Referentie&quot;">​</a></h2><h3 id="gangbare-rechtenaliassen" tabindex="-1">Gangbare rechtenaliassen <a class="header-anchor" href="#gangbare-rechtenaliassen" aria-label="Permalink to &quot;Gangbare rechtenaliassen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Rechten</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>chmod_000</code></td><td><code>----------</code></td><td>Geen rechten voor iedereen</td></tr><tr><td><code>chmod_400</code></td><td><code>r--------</code></td><td>Alleen-lezen voor de eigenaar</td></tr><tr><td><code>chmod_444</code></td><td><code>r--r--r--</code></td><td>Alleen-lezen voor iedereen</td></tr><tr><td><code>chmod_600</code></td><td><code>rw-------</code></td><td>Lezen/schrijven voor de eigenaar</td></tr><tr><td><code>chmod_644</code></td><td><code>rw-r--r--</code></td><td>Lezen/schrijven voor eigenaar, alleen-lezen voor anderen</td></tr><tr><td><code>chmod_666</code></td><td><code>rw-rw-rw-</code></td><td>Lezen/schrijven voor iedereen</td></tr><tr><td><code>chmod_755</code></td><td><code>rwxr-xr-x</code></td><td>Volledig voor eigenaar, lezen/uitvoeren voor anderen</td></tr><tr><td><code>chmod_764</code></td><td><code>rwxrw-r--</code></td><td>Volledig voor eigenaar, lezen/schrijven voor groep</td></tr><tr><td><code>chmod_777</code></td><td><code>rwxrwxrwx</code></td><td>Volledige rechten voor iedereen</td></tr></tbody></table><h3 id="eigenaarsrechten-aliassen" tabindex="-1">Eigenaarsrechten-aliassen <a class="header-anchor" href="#eigenaarsrechten-aliassen" aria-label="Permalink to &quot;Eigenaarsrechten-aliassen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>chmod_u+x</code></td><td>Voeg uitvoerrecht toe voor de eigenaar</td></tr><tr><td><code>chmod_u-x</code></td><td>Verwijder uitvoerrecht voor de eigenaar</td></tr><tr><td><code>chmod_u+w</code></td><td>Voeg schrijfrecht toe voor de eigenaar</td></tr><tr><td><code>chmod_u-w</code></td><td>Verwijder schrijfrecht voor de eigenaar</td></tr><tr><td><code>chmod_u+r</code></td><td>Voeg leesrecht toe voor de eigenaar</td></tr><tr><td><code>chmod_u-r</code></td><td>Verwijder leesrecht voor de eigenaar</td></tr></tbody></table><h3 id="groepsrechten-aliassen" tabindex="-1">Groepsrechten-aliassen <a class="header-anchor" href="#groepsrechten-aliassen" aria-label="Permalink to &quot;Groepsrechten-aliassen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>chmod_g+x</code></td><td>Voeg uitvoerrecht toe voor de groep</td></tr><tr><td><code>chmod_g-x</code></td><td>Verwijder uitvoerrecht voor de groep</td></tr><tr><td><code>chmod_g+w</code></td><td>Voeg schrijfrecht toe voor de groep</td></tr><tr><td><code>chmod_g-w</code></td><td>Verwijder schrijfrecht voor de groep</td></tr><tr><td><code>chmod_g+r</code></td><td>Voeg leesrecht toe voor de groep</td></tr><tr><td><code>chmod_g-r</code></td><td>Verwijder leesrecht voor de groep</td></tr></tbody></table><h3 id="anderenrechten-aliassen" tabindex="-1">Anderenrechten-aliassen <a class="header-anchor" href="#anderenrechten-aliassen" aria-label="Permalink to &quot;Anderenrechten-aliassen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>chmod_o+x</code></td><td>Voeg uitvoerrecht toe voor anderen</td></tr><tr><td><code>chmod_o-x</code></td><td>Verwijder uitvoerrecht voor anderen</td></tr><tr><td><code>chmod_o+w</code></td><td>Voeg schrijfrecht toe voor anderen</td></tr><tr><td><code>chmod_o-w</code></td><td>Verwijder schrijfrecht voor anderen</td></tr><tr><td><code>chmod_o+r</code></td><td>Voeg leesrecht toe voor anderen</td></tr><tr><td><code>chmod_o-r</code></td><td>Verwijder leesrecht voor anderen</td></tr></tbody></table><h3 id="bestandstype-aliassen" tabindex="-1">Bestandstype-aliassen <a class="header-anchor" href="#bestandstype-aliassen" aria-label="Permalink to &quot;Bestandstype-aliassen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>chmod_755d</code></td><td>Stel rechten van alle mappen in op <code>rwxr-xr-x</code></td></tr><tr><td><code>chmod_644f</code></td><td>Stel rechten van alle bestanden in op <code>rw-r--r--</code></td></tr></tbody></table><h3 id="recursieve-rechtenfunctie" tabindex="-1">Recursieve rechtenfunctie <a class="header-anchor" href="#recursieve-rechtenfunctie" aria-label="Permalink to &quot;Recursieve rechtenfunctie&quot;">​</a></h3><p>De <code>change_permission</code> functie past rechten recursief toe met een bevestigingsprompt:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',20)])])}const p=t(a,[["render",n]]);export{g as __pageData,p as default};
